    var a = 5
    var b = 10
    if(a >= b){
        print("a is greater or equal to b. ")
    }
    if(a == 0){
        print("a is 0. ")
    }
    if(a <= 5){
        print("a is not more than 5. ")
    }
    print("Program ends")
}
